function sanitize(str){return str.replace(/[<>"'&]/g,c=>({'<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;','&':'&amp;'}[c]));}
function validatePhone(ph){return /^[\d\s\+\-\(\)]{6,20}$/.test(ph);}
function submitOrder(){ const name = sanitize(document.getElementById('ordName').value.trim()); const phone = sanitize(document.getElementById('ordPhone').value.trim()); const addr = sanitize(document.getElementById('ordAddr').value.trim()); if(!name||!phone){toast('Completați numele și telefonul','info');return;} if(!validatePhone(phone)){toast('Număr de telefon invalid','info');return;} const total = cart.reduce((s,x)=>s+x.price*x.qty,0); const items = cart.map(it=>sanitize(it.brand)+' '+sanitize(it.series)+' x'+it.qty).join(', '); const waMsg = `Comandă nouă AiClima!\nNume: ${name}\nTelefon: ${phone}\nAdresă: ${addr||'—'}\nProduse: ${items}\nTotal: ${total.toLocaleString()} lei`; window.open('https://wa.me/37369439990?text='+encodeURIComponent(waMsg),'_blank'); cart=[];updCart();closeCheckout();closeCart(); toast('Comanda a fost trimisă! Vă vom contacta în scurt timp.','ok');
} /* ══ COMPARE ══ */
