const PAGE_CAT={split:'split',multi:'multi',caseta:'caseta'};
var pageQB={split:'all',multi:'all',caseta:'all'};
var pageMS={split:'all',multi:'all',caseta:'all'};
function goPage(pid){var page=pid.toLowerCase();showV('v'+pid);renderPage(page);navAct(document.getElementById('nav-'+page));mnAct(document.getElementById('mnb-catalog'));}
function getPageF(page){ var L=P.filter(function(p){return p.cat===PAGE_CAT[page];}); if(pageQB[page]!=='all')L=L.filter(function(p){return p.brand===pageQB[page];}); if(pageMS[page]&&pageMS[page]!=='all')L=L.filter(function(p){return p.series===pageMS[page];}); var ar=document.querySelector('.far-'+page+':checked'); if(ar){var v=parseInt(ar.value);if(v>0)L=L.filter(function(p){return p.area<=v;});} var pr=document.querySelector('.fpr-'+page+':checked'); if(pr){var vp=parseInt(pr.value);if(vp===99999)L=L.filter(function(p){return p.price>=20000;});else if(vp>0)L=L.filter(function(p){return p.price<=vp;});} if(colorFilterPage[page]&&colorFilterPage[page]!=='toate')L=L.filter(function(p){return p.color===colorFilterPage[page];}); var fs=document.getElementById('fstock-'+page);if(fs&&fs.checked)L=L.filter(function(p){return p.stock;}); var fw=document.getElementById('fwifi-'+page);if(fw&&fw.checked)L=L.filter(function(p){return p.wifi;}); var ec=document.querySelector('.fecls-'+page+':checked');if(ec&&ec.value!=='toate')L=L.filter(function(p){return p.cls===ec.value;}); var sv=document.getElementById('sort-'+page);if(sv){if(sv.value==='pa')L.sort(function(a,b){return a.price-b.price;});else if(sv.value==='pd')L.sort(function(a,b){return b.price-a.price;});} return L;
}
function renderPage(page){ var L=getPageF(page); var g=document.getElementById('grid-'+page); var c=document.getElementById('catCnt-'+page); if(c)c.textContent=L.length+' produse'; if(g)g.innerHTML=L.length?L.map(card).join(''):'<p style="grid-column:1/-1;text-align:center;padding:44px;color:var(--muted)">Nu s-au găsit produse.</p>'; g.querySelectorAll('.fade-in').forEach(function(el){el.classList.add('visible');}); setTimeout(observeFade,100);
}
function renderSeriesFilter(page){ var box=document.getElementById('mfilters-'+page); if(!box)return; var brand=pageQB[page]; if(brand==='all'){box.innerHTML='';return;} // unique series for this brand+category var pool=P.filter(function(p){return p.cat===PAGE_CAT[page]&&p.brand===brand;}); var seriesSet={}; pool.forEach(function(p){if(p.series)seriesSet[p.series]=true;}); var seriesList=Object.keys(seriesSet); if(seriesList.length<=1){box.innerHTML='';return;} var html='<span class="mf-lbl">Model:</span>'; html+='<button class="mf'+(pageMS[page]==='all'?' active':'')+'" onclick="qSeriesPage(\''+page+'\',\'all\',this)">Toate</button>'; seriesList.forEach(function(s){ var safe=s.replace(/'/g,"\\'"); html+='<button class="mf'+(pageMS[page]===s?' active':'')+'" onclick="qSeriesPage(\''+page+'\',\''+safe+'\',this)">'+s+'</button>'; }); box.innerHTML=html;
}
function applyPage(page){renderPage(page);}
function resetPage(page){ colorFilterPage[page]='toate'; document.querySelectorAll('#color-swatches-'+page+' .cswatch').forEach(function(s,i){s.classList.toggle('active',i===0);}); pageQB[page]='all'; pageMS[page]='all'; document.querySelectorAll('.far-'+page).forEach(function(c,i){c.checked=(i===0);}); document.querySelectorAll('.fpr-'+page).forEach(function(c,i){c.checked=(i===0);}); var fs=document.getElementById('fstock-'+page);if(fs)fs.checked=false; var fw=document.getElementById('fwifi-'+page);if(fw)fw.checked=false; document.querySelectorAll('.fecls-'+page).forEach(function(c,i){c.checked=(i===0);}); document.querySelectorAll('#bfilters-'+page+' .bf').forEach(function(b,i){b.classList.toggle('active',i===0);}); renderSeriesFilter(page); renderPage(page);
}
