/* ══ WEEK OFFER COUNTDOWN ══ */
function startWeekTimer(){ 
    function getTarget(){ 
        const now=new Date(); 
        const target=new Date(now); 
        const dayOfWeek=now.getDay(); 
        const daysUntilSunday=dayOfWeek===0?7:7-dayOfWeek; 
        target.setDate(now.getDate()+daysUntilSunday); 
        target.setHours(23,59,59,0); 
        return target; 
    } 
    const target=getTarget(); 
    function tick(){ 
        const now=new Date(); 
        const diff=target-now; 
        if(diff<=0){return;} 
        const days=Math.floor(diff/86400000); 
        const hours=Math.floor((diff%86400000)/3600000); 
        const mins=Math.floor((diff%3600000)/60000); 
        const secs=Math.floor((diff%60000)/1000); 
        const d=document.getElementById('wt-days'); 
        const h=document.getElementById('wt-hours'); 
        const m=document.getElementById('wt-mins'); 
        const s=document.getElementById('wt-secs'); 
        if(d)d.textContent=days; 
        if(h)h.textContent=String(hours).padStart(2,'0'); 
        if(m)m.textContent=String(mins).padStart(2,'0'); 
        if(s)s.textContent=String(secs).padStart(2,'0'); 
    } 
    tick(); 
    setInterval(tick,1000);
}

