var colorFilterCatalog='toate';
var colorFilterPage={split:'toate',multi:'toate',caseta:'toate'}; 

function setColorFilter(page,color,el){ 
    if(page==='catalog'){ 
        colorFilterCatalog=color; 
        document.querySelectorAll('#color-swatches-catalog .cswatch').forEach(function(s){s.classList.toggle('active',s.dataset.color===color);}); 
        applyF(); 
    } else { 
        colorFilterPage[page]=color; 
        document.querySelectorAll('#color-swatches-'+page+' .cswatch').forEach(function(s){s.classList.toggle('active',s.dataset.color===color);}); 
        applyPage(page); 
    }
}

